const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const dayOfYear = Math.floor((now - startOfYear) / 86400000);

const topics = [
  {
    categoria: "AI for entrepreneurs",
    feed_url: "https://news.google.com/rss/search?q=AI+startup+founder+small+business&hl=en-US&gl=US&ceid=US:en",
    enfoque: "opportunity"
  },
  {
    categoria: "AI tools for productivity",
    feed_url: "https://news.google.com/rss/search?q=AI+tools+productivity+small+business+automation&hl=en-US&gl=US&ceid=US:en",
    enfoque: "practical use"
  },
  {
    categoria: "AI risks for business",
    feed_url: "https://news.google.com/rss/search?q=AI+business+risk+mistake+automation+failure&hl=en-US&gl=US&ceid=US:en",
    enfoque: "risk awareness"
  },
  {
    categoria: "Real AI business cases",
    feed_url: "https://news.google.com/rss/search?q=AI+case+study+startup+growth&hl=en-US&gl=US&ceid=US:en",
    enfoque: "real example"
  },
  {
    categoria: "AI trends and opportunities",
    feed_url: "https://news.google.com/rss/search?q=AI+business+trend+opportunity&hl=en-US&gl=US&ceid=US:en",
    enfoque: "trend insight"
  }
];

const topicIndex = dayOfYear % topics.length;
const picked = topics[topicIndex];

return [
  {
    json: {
      fecha: now.toISOString().slice(0, 10),
      topic_index: topicIndex,
      categoria: picked.categoria,
      feed_url: picked.feed_url,
      enfoque: picked.enfoque,
      audience: "entrepreneurs and small business owners",
      brand_style: "modern, clean, premium",
      visual_direction: "editorial Instagram ad with strong focal point"
    }
  }
];

// Toma todos los items que vienen del RSS Read
const items = $input.all();

// Si no hay nada, devuelve vacío
if (!items.length) return [];

// Ordenar por fecha (isoDate) descendente
items.sort((a, b) => {
  const da = new Date(a.json.isoDate || a.json.pubDate || 0).getTime();
  const db = new Date(b.json.isoDate || b.json.pubDate || 0).getTime();
  return db - da;
});

// Quedarnos con el primero (más reciente)
return [items[0]];

// Toma el base64 de la respuesta de Gemini (inlineData.data)
const b64 = $json.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;

if (!b64) {
  throw new Error('No encontré inlineData.data en la respuesta. Revisa el path candidates[0].content.parts[].inlineData.data');
}

// Construye binario para n8n
item.binary = item.binary || {};
item.binary.image = {
  data: b64,                // base64 puro, sin "data:image/png;base64,"
  mimeType: 'image/png',
  fileName: `imagen_${Date.now()}.png`,

};

return item;
